import{_ as a,o as s,c as i,aA as t}from"./chunks/framework.CebKgM-l.js";const k=JSON.parse('{"title":"The .krk DSL — overview","description":"","frontmatter":{},"headers":[],"relativePath":"krk/overview.md","filePath":"krk/overview.md","lastUpdated":null}'),n={name:"krk/overview.md"};function r(l,e,o,p,h,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="The-.krk-DSL-—-overview" tabindex="-1">The .krk DSL — overview <a class="header-anchor" href="#The-.krk-DSL-—-overview" aria-label="Permalink to &quot;The .krk DSL — overview {#The-.krk-DSL-—-overview}&quot;">​</a></h1><p>Kraken exposes two equivalent entry points to the LBM solver:</p><ol><li><p>The <strong>Julia API</strong> (<code>run_cavity_2d(...)</code>, <code>run_simulation(&quot;file.krk&quot;)</code>, and friends) — documented in the <a href="./../api/drivers">Julia API reference</a>. Use it when you want full programmatic control, scripting, or plotting inside a notebook.</p></li><li><p>The <strong>.krk configuration format</strong> — a small declarative DSL parsed by <code>src/io/kraken_parser.jl</code>. Use it when you want a self-contained, human-readable description of a run that can be version-controlled, shared, diffed, and swept with kwarg overrides.</p></li></ol><h2 id="Philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#Philosophy" aria-label="Permalink to &quot;Philosophy {#Philosophy}&quot;">​</a></h2><ul><li><p><strong>Declarative, not imperative.</strong> A .krk file describes <em>what</em> the simulation is (geometry, physics, boundary conditions), not <em>how</em> to step it. The solver picks the runner.</p></li><li><p><strong>Gerris-flavored syntax.</strong> Line-oriented, one directive per line, curly braces for blocks, <code>#</code> for comments. No TOML / YAML / JSON.</p></li><li><p><strong>One source of truth.</strong> Every directive maps to a function in <code>src/io/kraken_parser.jl</code>; presets expand into plain .krk lines so that <code>Preset cavity_2d</code> is exactly equivalent to writing the expanded block by hand.</p></li><li><p><strong>Fail loudly at parse time.</strong> The parser runs sanity checks (tau, Mach), validates face names against the lattice dimension, and offers Levenshtein &quot;did you mean?&quot; suggestions on typos.</p></li></ul><h2 id="Minimal-example" tabindex="-1">Minimal example <a class="header-anchor" href="#Minimal-example" aria-label="Permalink to &quot;Minimal example {#Minimal-example}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 2D lid-driven cavity at Re = 100</span></span>
<span class="line"><span>Simulation cavity D2Q9</span></span>
<span class="line"><span>Domain     L = 1.0 x 1.0   N = 128 x 128</span></span>
<span class="line"><span>Physics    nu = 0.01</span></span>
<span class="line"><span>Boundary   north velocity(ux = 0.1, uy = 0)</span></span>
<span class="line"><span>Boundary   south wall</span></span>
<span class="line"><span>Boundary   east  wall</span></span>
<span class="line"><span>Boundary   west  wall</span></span>
<span class="line"><span>Run        10000 steps</span></span></code></pre></div><p>Run it from Julia:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Kraken</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">setup </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> load_kraken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cavity.krk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">run_simulation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(setup)                    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or run_simulation(&quot;cavity.krk&quot;)</span></span></code></pre></div><p>Override parameters without editing the file (parametric studies):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">setup </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> load_kraken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cavity.krk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; Re</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">400</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, N</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="When-to-use-what" tabindex="-1">When to use what <a class="header-anchor" href="#When-to-use-what" aria-label="Permalink to &quot;When to use what {#When-to-use-what}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Use .krk if you...</th><th style="text-align:right;">Use the Julia API if you...</th></tr></thead><tbody><tr><td style="text-align:right;">want a reproducible run description</td><td style="text-align:right;">want to script / loop / plot inline</td></tr><tr><td style="text-align:right;">are sharing with a collaborator</td><td style="text-align:right;">need custom post-processing hooks</td></tr><tr><td style="text-align:right;">are sweeping parameters</td><td style="text-align:right;">need non-standard runners</td></tr><tr><td style="text-align:right;">prefer declarative configs</td><td style="text-align:right;">prefer direct control</td></tr></tbody></table><h2 id="Reference-structure" tabindex="-1">Reference structure <a class="header-anchor" href="#Reference-structure" aria-label="Permalink to &quot;Reference structure {#Reference-structure}&quot;">​</a></h2><p>The rest of this section documents every piece of the DSL:</p><ul><li><p><a href="./directives">Directives</a> — all top-level keywords</p></li><li><p><a href="./bc_types">Boundary condition types</a> — <code>wall</code>, <code>velocity</code>, <code>pressure</code>, …</p></li><li><p><a href="./modules">Modules</a> — public and parser-only modules</p></li><li><p><a href="./presets">Presets</a> — 5 built-in canonical cases</p></li><li><p><a href="./helpers">Setup helpers</a> — <code>reynolds</code>, <code>rayleigh</code>, <code>prandtl</code></p></li><li><p><a href="./expressions">Expressions</a> — the KrakenExpr grammar</p></li><li><p><a href="./sanity">Sanity checks</a> — tau and Mach bounds at parse time</p></li><li><p><a href="./errors">Error messages</a> — common errors and fixes</p></li><li><p><a href="./aliases">Face aliases</a> — dimension- and module-dependent face names</p></li></ul>`,16)])])}const u=a(n,[["render",r]]);export{k as __pageData,u as default};
